// 解析请求并准备搜索参数
const input = $input.first().json;

const searchQueries = {
  github: {
    topics: input.topics || [],
    languages: input.languages || ['Python', 'JavaScript'],
    minStars: input.minStars || 100
  },
  youtube: {
    keywords: input.keywords || [],
    channels: input.preferredChannels || [],
    uploadDate: 'this_year'
  },
  courses: {
    platforms: ['coursera', 'udemy', 'edx'],
    level: input.level || 'all',
    price: input.pricePreference || 'any'
  }
};

return {
  json: {
    searchQueries,
    userId: input.userId || 'anonymous',
    timestamp: new Date().toISOString()
  }
};

