// 处理 AI 推荐的资源并添加元数据
const aiResponse = $input.first().json.output;

let recommendations = typeof aiResponse === 'string' 
  ? JSON.parse(aiResponse) 
  : aiResponse;

// 为每个资源添加元数据和追踪信息
const enrichedRecommendations = recommendations.recommendations?.map((rec, index) => ({
  ...rec,
  metadata: {
    recommendedAt: new Date().toISOString(),
    recommendationId: `rec_${Date.now()}_${index}`,
    aiModel: 'gpt-4o',
    version: '1.0'
  },
  tracking: {
    viewed: false,
    saved: false,
    completed: false,
    rating: null,
    feedback: null
  },
  relatedResources: [],
  nextSteps: []
}));

return {
  json: {
    status: 'success',
    recommendations: enrichedRecommendations,
    learningPath: recommendations.learningPath,
    tips: recommendations.tips,
    totalResults: enrichedRecommendations.length,
    generatedAt: new Date().toISOString()
  }
};

// 定时任务：更新热门资源
const trendingTopics = [
  'llm', 'transformer', 'diffusion', 'rag', 'agent',
  'fine-tuning', 'prompt-engineering', 'vector-database'
];

return {
  json: {
    type: 'trending_update',
    topics: trendingTopics,
    scheduledAt: new Date().toISOString()
  }
};
